{
  "lessons": [
    {
      "description": "Reconoce y construye la estructura básica de la segunda condicional: 'If + pasado simple, would + verbo base', para hablar de situaciones hipotéticas en presente o futuro.",
      "kind": "grammar",
      "title": "Estructura de la segunda condicional"
    },
    {
      "description": "Usa 'were' en lugar de 'was' con todos los sujetos (I were, he were, she were) dentro de la cláusula hipotética con 'if', incluyendo la expresión fija 'If I were you'.",
      "kind": "grammar",
      "title": "Uso de 'were' en la cláusula hipotética"
    },
    {
      "description": "Compara oraciones con 'would', 'could' y 'might' en la parte principal de la condicional para expresar diferentes grados de certeza, posibilidad y capacidad en resultados hipotéticos.",
      "kind": "grammar",
      "title": "Would, could y might en resultados hipotéticos"
    },
    {
      "description": "Distingue cuándo usar la primera condicional para situaciones futuras reales o probables frente a la segunda condicional para situaciones hipotéticas o improbables.",
      "kind": "grammar",
      "title": "Primera condicional vs. segunda condicional"
    },
    {
      "description": "Reconoce y practica variaciones de orden en las oraciones condicionales, incluyendo invertir la cláusula 'if' y la cláusula principal, con y sin coma.",
      "kind": "grammar",
      "title": "Orden de las cláusulas en oraciones condicionales"
    },
    {
      "description": "Reconoce y usa frases hipotéticas comunes como 'If I were you, I would...', 'What would you do if...?' e 'I wish I could...' en conversaciones cotidianas.",
      "kind": "vocabulary",
      "title": "Frases hipotéticas comunes"
    }
  ]
}

